import { useMemo } from 'react';

import { formatResolution } from '../../../utils/resolution-formatter.js';
import { ResolutionLabel } from '../ResolutionLabel.js';

export const TimeResolution = (props: { from: Date; to: Date }) => {
  const { from, to } = props;
  const resolution = useMemo(() => formatResolution(from, to), [from, to]);

  return <ResolutionLabel text={resolution} />;
};

TimeResolution['displayName'] = 'TimeResolution';
